// EDTMRS - Alerts Page
import React, { useState, useEffect, useCallback } from 'react';
import { alertsAPI } from '../utils/api';
import RiskBadge from '../components/RiskBadge';

const SEVERITY_CONFIG = {
  critical: { bg: 'bg-red-500/10',    border: 'border-red-500/30',    text: 'text-red-400'    },
  high:     { bg: 'bg-orange-500/10', border: 'border-orange-500/30', text: 'text-orange-400' },
  medium:   { bg: 'bg-yellow-500/10', border: 'border-yellow-500/30', text: 'text-yellow-400' },
  low:      { bg: 'bg-blue-500/10',   border: 'border-blue-500/30',   text: 'text-blue-400'   },
};

export default function AlertsPage({ liveEvents, onAlertCountChange }) {
  const [alerts, setAlerts]   = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter]   = useState('unread');
  const [toast, setToast]     = useState('');

  const fetchAlerts = useCallback(async () => {
    try {
      const params = {};
      if (filter === 'unread')  params.acknowledged = false;
      if (filter === 'read')    params.acknowledged = true;
      const res = await alertsAPI.list(params);
      setAlerts(res.data.alerts);
      // Count unread
      if (filter !== 'read') {
        onAlertCountChange?.(res.data.alerts.filter(a => !a.is_acknowledged).length);
      }
    } finally { setLoading(false); }
  }, [filter, onAlertCountChange]);

  useEffect(() => { fetchAlerts(); }, [fetchAlerts]);
  useEffect(() => { if (liveEvents?.length) fetchAlerts(); }, [liveEvents, fetchAlerts]);

  const ack = async (id) => {
    await alertsAPI.acknowledge(id);
    fetchAlerts();
  };

  const ackAll = async () => {
    await alertsAPI.acknowledgeAll();
    setToast('All alerts acknowledged');
    setTimeout(() => setToast(''), 3000);
    fetchAlerts();
  };

  const unreadCount = alerts.filter(a => !a.is_acknowledged).length;

  return (
    <div className="space-y-5">
      {toast && (
        <div className="fixed top-5 right-5 z-50 px-4 py-3 bg-emerald-600/20 border border-emerald-500/40 text-emerald-400 rounded-xl text-sm shadow-xl">
          ✓ {toast}
        </div>
      )}

      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-xl font-bold text-white">Alerts</h1>
          <p className="text-gray-500 text-sm mt-0.5">Suspicious device connection alerts</p>
        </div>
        {unreadCount > 0 && (
          <button onClick={ackAll}
            className="px-4 py-2 bg-blue-600/20 hover:bg-blue-600/30 border border-blue-500/40 text-blue-400 rounded-lg text-sm font-medium transition-all">
            ✓ Acknowledge All ({unreadCount})
          </button>
        )}
      </div>

      {/* Filter tabs */}
      <div className="flex gap-2">
        {['unread', 'read', 'all'].map((f) => (
          <button key={f} onClick={() => setFilter(f)}
            className={`px-4 py-2 rounded-lg text-sm font-medium capitalize transition-all ${
              filter === f ? 'bg-blue-600 text-white' : 'bg-[#0f1629] border border-[#1e2d4d] text-gray-400 hover:text-white'
            }`}>
            {f === 'unread' ? `Unread${unreadCount ? ` (${unreadCount})` : ''}` : f === 'read' ? 'Acknowledged' : 'All'}
          </button>
        ))}
      </div>

      {/* Alert list */}
      {loading ? (
        <div className="flex justify-center py-16">
          <div className="w-8 h-8 border-2 border-blue-500/30 border-t-blue-400 rounded-full animate-spin" />
        </div>
      ) : !alerts.length ? (
        <div className="text-center py-20 text-gray-600 bg-[#0f1629] border border-[#1e2d4d] rounded-xl">
          <div className="text-4xl mb-3">✓</div>
          <div className="text-white text-lg font-semibold mb-1">No alerts</div>
          <div className="text-sm">
            {filter === 'unread' ? 'All clear — no unread alerts.' : 'No alerts in this category.'}
          </div>
        </div>
      ) : (
        <div className="space-y-3">
          {alerts.map((a) => {
            const sev = SEVERITY_CONFIG[a.severity] || SEVERITY_CONFIG.medium;
            return (
              <div key={a.id}
                className={`rounded-xl border p-5 transition-all ${
                  a.is_acknowledged
                    ? 'bg-[#0f1629] border-[#1e2d4d] opacity-60'
                    : `${sev.bg} ${sev.border}`
                }`}>
                <div className="flex items-start justify-between gap-4">
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2.5 mb-2 flex-wrap">
                      <RiskBadge level={a.severity} pulse={!a.is_acknowledged} />
                      <span className="text-gray-500 text-xs">Alert #{a.id}</span>
                      {!a.is_acknowledged && (
                        <span className="px-1.5 py-0.5 bg-blue-500/20 text-blue-400 text-[10px] font-bold rounded uppercase tracking-wider">New</span>
                      )}
                    </div>
                    <p className="text-gray-300 text-sm leading-relaxed mb-3">{a.message}</p>
                    <div className="flex flex-wrap gap-x-5 gap-y-1 text-xs text-gray-500">
                      {a.hostname       && <span>Host: <span className="text-gray-400">{a.hostname}</span></span>}
                      {a.username       && <span>User: <span className="text-gray-400">{a.username}</span></span>}
                      {a.device_name    && <span>Device: <span className="text-gray-400">{a.device_name}</span></span>}
                      {a.drive_letter   && <span>Drive: <span className="text-gray-400 font-mono">{a.drive_letter}</span></span>}
                      {a.serial_number && a.serial_number !== 'unknown' && (
                        <span>S/N: <span className="text-gray-400 font-mono">{a.serial_number}</span></span>
                      )}
                      <span>Time: <span className="text-gray-400">{new Date(a.created_at).toLocaleString()}</span></span>
                    </div>
                  </div>
                  {!a.is_acknowledged && (
                    <button onClick={() => ack(a.id)}
                      className="flex-shrink-0 px-3 py-1.5 bg-white/5 hover:bg-white/10 border border-white/10 text-gray-400 hover:text-white rounded-lg text-xs transition-all">
                      ✓ Ack
                    </button>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
